  'auto-blog-train-street-007': {en:"The train passing through Train Street — just inches from local homes and cafés", vn:"Đoàn tàu chạy qua Train Street — chỉ cách nhà dân và quán cà phê vài inch"},
  'auto-blog-train-street-008': {en:"Train Street is one of the most unusual places in Hanoi.", vn:"Train Street là một trong những nơi độc đáo nhất ở Hà Nội."},
  'auto-blog-train-street-009': {en:"A narrow residential street. Homes just inches from the tracks. Cafés set up right beside them. And a train that passes through it all, just a few times each day.", vn:"Một con phố nhỏ. Nhà dân sát đường ray. Quán cà phê ngay bên cạnh. Và đoàn tàu chạy qua chỉ cách vài bước chân."},
  'auto-blog-train-street-010': {en:"It's not built for tourists—but that's exactly why people come.", vn:"Nơi này không được xây dựng cho du lịch—nhưng chính điều đó lại khiến nó trở nên đặc biệt."},
  'auto-blog-train-street-011': {en:"What is Train Street?", vn:"Train Street là gì?"},
  'auto-blog-train-street-012': {en:"Train Street is a stretch of railway running through a residential neighborhood in central Hanoi.", vn:"Đây là đoạn đường ray chạy xuyên qua khu dân cư ở trung tâm Hà Nội."},
  'auto-blog-train-street-013': {en:"Locals live, cook, and run small cafés right next to the tracks. When the train approaches, everything shifts. Chairs are moved. People step back. Then the train passes—and life continues.", vn:"Người dân sinh sống, nấu ăn và kinh doanh ngay cạnh đường ray. Khi tàu đến, mọi thứ thay đổi—ghế được dọn đi, mọi người đứng lùi lại. Khi tàu qua, cuộc sống tiếp tục như bình thường."},
  'auto-blog-train-street-014': {en:"Is Train Street still open in 2026?", vn:"Train Street còn mở không năm 2026?"},
  'auto-blog-train-street-015': {en:"This is one of the most common questions.", vn:"Đây là câu hỏi rất nhiều người quan tâm."},
