  'auto-our-story-029': {en:"What started as one unfinished space in Hanoi slowly became MiaCasa.", vn:"Một không gian chưa hoàn thiện ở Hà Nội đã dần trở thành MiaCasa."},
  'auto-our-story-030': {en:"Piece by piece", vn:"Từng món một"},
  'auto-our-story-031': {en:"Furniture was chosen slowly. Some pieces took weeks. Others were rebuilt until they felt right.", vn:"Nội thất được chọn dần dần. Có món phải mất nhiều tuần. Có món được làm lại nhiều lần cho đến khi ưng ý."},
  'auto-our-story-032': {en:"Not just for photos", vn:"Không chỉ đẹp trong ảnh"},
  'auto-our-story-033': {en:"We never wanted a space that looked perfect only in photos. We wanted it to feel good to come home to.", vn:"Chúng tôi không muốn tạo ra không gian chỉ đẹp trong ảnh. Chúng tôi muốn nó là nơi bạn muốn trở về."},
  'auto-our-story-034': {en:"Perfectly located", vn:"Vị trí lý tưởng"},
  'auto-our-story-035': {en:"MiaCasa Hanoi — quiet, tucked from noise, yet close to Văn Miếu, Train Street, Ba Đình, Hoàn Kiếm Lake, and the Old Quarter.", vn:"MiaCasa Hà Nội — yên tĩnh, tránh xa ồn ào, nhưng gần Văn Miếu, Phố Tàu, Ba Đình, Hồ Hoàn Kiếm và Phố Cổ."},
  'auto-our-story-036': {en:"Learning by doing", vn:"Học qua thực hành"},
  'auto-our-story-037': {en:"We learned how lighting changes a room. How small comforts matter. How thoughtful design creates restfulness — even in a busy city.", vn:"Chúng tôi học được cách ánh sáng thay đổi căn phòng. Những tiện nghi nhỏ quan trọng thế nào. Thiết kế chu đáo tạo ra sự thư thái ra sao — ngay cả giữa lòng thành phố nhộn nhịp."},
  'auto-our-story-038': {en:"Not luxury — just real", vn:"Không sang trọng — chỉ chân thật"},
  'auto-our-story-039': {en:"Not luxury in the traditional sense. Just spaces that feel personal, calm, and genuinely cared for.", vn:"Không phải xa xỉ theo nghĩa truyền thống. Chỉ là những không gian mang cảm giác cá nhân, yên bình và thực sự được chăm chút."},
