  'auto-our-story-049': {en:"A quieter neighborhood stay near Văn Miếu and Train Street, designed for solo travelers and couples looking for a calmer rhythm within the city.", vn:"Một nơi lưu trú yên tĩnh hơn gần Văn Miếu và Phố Tàu, được thiết kế cho khách du lịch một mình và các cặp đôi đang tìm kiếm nhịp điệu bình yên hơn trong thành phố."},
  'auto-our-story-050': {en:"3 private studio-style rooms", vn:"3 phòng studio riêng tư"},
