  'auto-our-story-059': {en:"Walking distance to Hoàn Kiếm Lake, food streets, and nightlife", vn:"Đi bộ đến Hồ Hoàn Kiếm, phố ẩm thực và cuộc sống về đêm"},
  'auto-our-story-060': {en:"Explore Old Quarter →", vn:"Khám phá Phố Cổ →"},
  'auto-our-story-061': {en:"Different atmosphere. Same philosophy.", vn:"Bầu không khí khác nhau. Cùng một triết lý."},
  'auto-our-story-062': {en:"Why Travelers Choose MiaCasa in Hanoi", vn:"Tại sao du khách chọn MiaCasa tại Hà Nội"},
  'auto-our-story-063': {en:"Locally hosted, not remote", vn:"Chủ nhà tại chỗ, không qua trung gian"},
