  'auto-best-cafes-hanoi-001': {en:"Hanoi is a city best experienced slowly.", vn:"Hà Nội là thành phố nên được cảm nhận thật chậm."},
  'auto-best-cafes-hanoi-002': {en:"Not only through its landmarks and busy streets, but through its cafés — hidden courtyards, quiet upper floors, old apartments overlooking tree-lined roads, and small local spaces where conversations stretch longer than expected.", vn:"Không chỉ qua những địa danh nổi tiếng hay các con phố nhộn nhịp, mà còn qua những quán cà phê nhỏ, những khoảng sân yên tĩnh và các căn hộ cũ nhìn ra hàng cây xanh."},
  'auto-best-cafes-hanoi-003': {en:"Whether you are visiting Hanoi for a few days or staying longer, finding the right café often becomes part of the rhythm of the trip itself.", vn:"Việc tìm được một quán cà phê phù hợp thường trở thành một phần trong nhịp sống của chuyến đi."},
